sequenceDiagram(name = "CollisionAvoidance") {
    val camera = lifeline(name = "Camera")
    val radar = lifeline(name = "Radar")
    val fusion = lifeline(name = "FusionUnit")
    val assistant = lifeline(name = "EmergencyBrakingAssistant")
    val driver = lifeline(name = "Driver") { isActor = true }
    val control = lifeline(name = "BrakeControlUnit")
    val log = lifeline(name = "DiagnosticLog")

    message(from = camera, to = fusion, label = "cameraData()")
    message(from = radar, to = fusion, label = "radarData()")

    message(from = fusion, to = fusion, label = "computeEnvironmentModel()")
    message(from = fusion, to = assistant, label = "reportCollisionRisk(timeToCollision)")

    alt(condition = "timeToCollision < criticalThreshold") {
        message(from = assistant, to = driver, label = "acousticWarning()")
        message(from = assistant, to = control, label = "initiateAutonomousBraking()")
        loop(guard = "vehicle not stationary") {
            message(from = assistant, to = control, label = "adjustBrakePressure()")
        }
        message(from = assistant, to = control, label = "endBrakingManeuver()")
        message(from = assistant, to = log, label = "recordEvent()")
    } elseBranch {
        message(from = assistant, to = driver, label = "distanceWarning()")
        message(from = assistant, to = log, label = "logObservedRisk()")
    }
}

